import { GoogleGenAI } from "@google/genai";

// Note: Using the API key provided in the context. 
// In a production environment, this should be an environment variable.
const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const generateDashboardInsights = async (analytics: any): Promise<string> => {
  if (!analytics || analytics.totalRespondents === 0) {
    return "Insufficient data to generate insights.";
  }

  const prompt = `
    You are an AI Data Analyst for Laguna University. 
    Analyze the following alumni tracking data and provide a professional, concise interpretation and 3 valuable strategic insights for the university administration.

    **Data Overview:**
    - Total Respondents: ${analytics.totalRespondents}
    - Employed: ${analytics.employedCount}
    - Self-Employed: ${analytics.selfEmployedCount}
    - Unemployed: ${analytics.unemployedCount}
    - Retired: ${analytics.retiredCount}

    **Top Industries:**
    ${analytics.industryData.map((i: any) => `- ${i.name}: ${i.value}`).join('\n')}

    **Top Unemployment Reasons:**
    ${analytics.unemploymentReasonData.map((i: any) => `- ${i.name}: ${i.value}`).join('\n')}

    **Job Alignment:**
    - Related to Course: ${analytics.alignmentRate.find((r: any) => r.name === 'Related')?.value || 0}
    - Non-Related: ${analytics.alignmentRate.find((r: any) => r.name === 'Non-Related')?.value || 0}

    **Top Misalignment Reasons:**
    ${analytics.alignmentReasonData.map((i: any) => `- ${i.name}: ${i.value}`).join('\n')}

    **Output Format:**
    Provide a "Key Interpretation" paragraph (max 2 sentences) summarizing the overall employment health.
    Then list "Strategic Insights" (bullet points) focusing on curriculum improvements, career guidance interventions, or industry partnerships.
    Do not use markdown bolding for the whole text, just for headers.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts: [{ text: prompt }] },
    });

    return response.text || "No insights available.";
  } catch (error) {
    console.error("AI Insight Error:", error);
    return "Unable to generate insights at this moment.";
  }
};

