  selfEmployedCount: number;
  retiredCount: number;
  industryData: { name: string; value: number }[];
  unemploymentReasonData: { name: string; value: number }[];
  alignmentReasonData: { name: string; value: number }[];
  retirementReasonData: { name: string; value: number }[];
  jobLevelData: { name: string; value: number }[];
  alignmentRate: { name: string; value: number }[];
}

// Master record type that combines employment info with user profile info
interface MasterRecord {
    employment_status: string;
    industry?: string;
    unemployed_reasons?: string;
    alignment_reason?: string;
    retirement_reason?: string;
    job_alignment?: string;
    current_job_level?: string;
    current_position?: string;
    company_name?: string;
    business_name?: string;

    // Detailed Info for Modal
    company_address?: string;
    business_address?: string;
    date_hired?: string;
    business_duration?: string;
    business_type?: string;
    business_contact_no?: string;
    date_retired?: string;
    last_company?: string;

    // Profile Data
    full_name: string;
    program: string;
    year_level: string; // Batch
}

// Helper Component for Interpretation
const AIInterpretation = ({ text, loading }: { text?: string, loading: boolean }) => (
    <div className="mt-6 pt-4 border-t border-gray-100 bg-indigo-50/50 -mx-6 -mb-6 px-6 py-4 rounded-b-3xl">
        <div className="flex gap-3 items-start">
            <div className="p-1.5 bg-indigo-100 rounded-lg text-indigo-600 shrink-0 mt-0.5">
                <Sparkles size={14} />
            </div>
            <div className="flex-grow">
                <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider mb-1">AI Interpretation</p>
                {loading ? (
                   <div className="space-y-2 animate-pulse max-w-xs">
                       <div className="h-2 bg-gray-200 rounded w-full"></div>
                       <div className="h-2 bg-gray-200 rounded w-5/6"></div>
                   </div>
                ) : (
                   <p className="text-xs text-gray-600 leading-relaxed font-medium">
                       {text || "Data insufficient for interpretation."}
                   </p>
                )}
            </div>
        </div>
    </div>
);

const HomePage: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [masterData, setMasterData] = useState<MasterRecord[]>([]);

  // Navigation Tabs
  const [activeTab, setActiveTab] = useState<'employment' | 'education' | 'community' | 'skills'>('employment');

  // Filters
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedCourse, setSelectedCourse] = useState<string>('All');
  const [availableYears, setAvailableYears] = useState<string[]>([]);

  // Modal State
  const [selectedStatusDetail, setSelectedStatusDetail] = useState<string | null>(null);

  // AI Insights State
  const [interpretations, setInterpretations] = useState<CardInterpretations | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Analytics State (Derived)
  const [analytics, setAnalytics] = useState<AnalyticsState>({
    totalRespondents: 0,
    employedCount: 0,
    unemployedCount: 0,
    selfEmployedCount: 0,
    retiredCount: 0,
    industryData: [],
    unemploymentReasonData: [],
    alignmentReasonData: [],
    retirementReasonData: [],
    jobLevelData: [],
    alignmentRate: []
  });

  // --- 1. Data Fetching (Joins Employment with User Profile) ---
  const fetchData = async () => {
      setLoading(true);
      try {
        // A. Fetch all employment records
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('*');

        if (empError) throw empError;
        if (!empData) return;

        // B. Fetch all survey responses to map Employment -> User ID
        const surveyIds = empData.map(e => e.survey_response_id);
        const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type')
            .in('id', surveyIds);

        if (surveyError) throw surveyError;

        // C. Fetch User Profiles (Students & Alumni) to get Program/Year/Names
        // We need to fetch all to map them efficiently locally
        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, first_name, last_name, program, year_level'),
            supabase.from('alumni').select('id, first_name, last_name, program, year_level')
        ]);

        // D. Build Maps for fast lookup
        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));
        const surveyMap = new Map(surveyData?.map((s: any) => [s.id, s]));

        // E. Construct Master Records
        const combined: MasterRecord[] = [];

        empData.forEach(record => {
            const survey = surveyMap.get(record.survey_response_id) as any;
            if (!survey) return;

            let userProfile: any = null;
            if (survey.respondent_type === 'student') {
                userProfile = studentMap.get(survey.student_id);
            } else {
                userProfile = alumniMap.get(survey.alumni_id);
            }

            if (userProfile) {
                // Normalize Year Level if needed
                const year = userProfile.year_level || 'Unknown';
                const fullName = `${userProfile.last_name}, ${userProfile.first_name}`;

                combined.push({
                    employment_status: record.employment_status,
                    industry: record.industry,
                    unemployed_reasons: record.unemployed_reasons,
                    alignment_reason: record.alignment_reason,
                    retirement_reason: record.retirement_reason,
                    job_alignment: record.job_alignment,
                    current_job_level: record.current_job_level,
                    current_position: record.current_position,
                    company_name: record.company_name,
                    business_name: record.business_name,

                    // Details
                    company_address: record.company_address,
                    business_address: record.business_address,
                    date_hired: record.date_hired,
                    business_duration: record.business_duration,
                    business_type: record.business_type,
                    business_contact_no: record.business_contact_no,
                    date_retired: record.date_retired,
                    last_company: record.last_company,

                    full_name: fullName,
                    program: userProfile.program || 'Unknown',
                    year_level: year
                });
            }
        });

        // Set Available Years for Filter (Static 2026-2006)
        const staticYears = [];
        for (let y = 2026; y >= 2006; y--) {
            staticYears.push(y.toString());
        }
        setAvailableYears(staticYears);

        setMasterData(combined);

      } catch (err) {
          console.error("Data fetch error:", err);
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- 2. Filter Logic & Calculation ---
  useEffect(() => {
    // A. Apply Filters
    const filtered = masterData.filter(record => {
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        // Basic inclusion check for program to handle slight variations, or exact match if preferred
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesYear && matchesCourse;
    });

    // B. Calculate Analytics based on Filtered Data
    const total = filtered.length;
    const employed = filtered.filter(r => r.employment_status === 'Employed').length;
    const selfEmployed = filtered.filter(r => r.employment_status === 'Self-employed').length;
    const unemployed = filtered.filter(r => r.employment_status === 'Unemployed').length;
    const retired = filtered.filter(r => r.employment_status === 'Retired').length;

    // Maps for charts
    const industryMap: Record<string, number> = {};
    const unempReasonMap: Record<string, number> = {};
    const misalignMap: Record<string, number> = {};
    const retireMap: Record<string, number> = {};
    const jobLevelMap: Record<string, number> = {};

    let relatedCount = 0;
    let nonRelatedCount = 0;

    filtered.forEach(r => {
        // Industry
        if (r.industry) industryMap[r.industry] = (industryMap[r.industry] || 0) + 1;

        // Unemployed Reasons
        if (r.unemployed_reasons) unempReasonMap[r.unemployed_reasons] = (unempReasonMap[r.unemployed_reasons] || 0) + 1;

        // Misalignment
        if (r.alignment_reason) misalignMap[r.alignment_reason] = (misalignMap[r.alignment_reason] || 0) + 1;

        // Retirement
        if (r.retirement_reason) retireMap[r.retirement_reason] = (retireMap[r.retirement_reason] || 0) + 1;

        // Job Level (Only if something is set)
        if (r.current_job_level && r.current_job_level !== 'N/A') {
             jobLevelMap[r.current_job_level] = (jobLevelMap[r.current_job_level] || 0) + 1;
        }

        // Alignment Rate
        if (r.job_alignment === 'Related') relatedCount++;
        if (r.job_alignment === 'Non-Related') nonRelatedCount++;
    });

    // Format for Recharts
    const formatChartData = (map: Record<string, number>, topN = 5) => 
        Object.entries(map)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, topN);

    const calculatedAnalytics = {
        totalRespondents: total,
        employedCount: employed,
        selfEmployedCount: selfEmployed,
        unemployedCount: unemployed,
        retiredCount: retired,
        industryData: formatChartData(industryMap),
        unemploymentReasonData: formatChartData(unempReasonMap),
        alignmentReasonData: formatChartData(misalignMap),
        retirementReasonData: formatChartData(retireMap),
        jobLevelData: formatChartData(jobLevelMap),
        alignmentRate: [
            { name: 'Related', value: relatedCount },
            { name: 'Non-Related', value: nonRelatedCount }
        ]
    };

    setAnalytics(calculatedAnalytics);

    // Call AI Service
    if (total > 0 && activeTab === 'employment') {
        const fetchInsights = async () => {
            setLoadingInsights(true);
            const data = await generateCardInterpretations(calculatedAnalytics);
            setInterpretations(data);
            setLoadingInsights(false);
        };
        fetchInsights();
    }

  }, [masterData, selectedYear, selectedCourse, activeTab]);

  // Derived filtered list for the modal
  const modalData = useMemo(() => {
    if (!selectedStatusDetail) return [];
    // Apply the same global filters (Year/Course) to the modal list
    return masterData.filter(record => {
        const matchesStatus = record.employment_status === selectedStatusDetail;
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesStatus && matchesYear && matchesCourse;
    });
  }, [selectedStatusDetail, masterData, selectedYear, selectedCourse]);

  const getPercent = (count: number) => {
      if (analytics.totalRespondents === 0) return 0;
      return Math.round((count / analytics.totalRespondents) * 100);
  };

  // Custom label for Pie Chart
  const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
    const x = cx + radius * Math.cos(-midAngle * (Math.PI / 180));
    const y = cy + radius * Math.sin(-midAngle * (Math.PI / 180));

    return (
      <text x={x} y={y} fill="white" textAnchor="middle" dominantBaseline="central" className="text-[10px] font-bold pointer-events-none">
        {`${(percent * 100).toFixed(0)}%`}
      </text>
    );
  };

  const handlePrint = () => {
    window.print();
  };

  // Reusable Component for Reason Lists
  const ReasonListCard = ({ 
    title, 
    icon: Icon, 
    data, 
    colorClass, 
    barColorClass,
    interpretation 
  }: { 
    title: string, 
    icon: any, 
    data: { name: string, value: number }[],
    colorClass: string,
    barColorClass: string,
    interpretation?: string
  }) => {
    const maxValue = Math.max(...data.map(d => d.value), 1);

    return (
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col h-full justify-between">
            <div>
                <div className="flex items-center gap-3 mb-6">
                    <div className={`p-2 rounded-lg ${colorClass}`}>
                        <Icon size={20}/>
                    </div>
                    <h4 className="font-bold text-gray-800">{title}</h4>
                </div>

                <div className="space-y-4 mb-4">
                    {data.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-32 text-gray-400">
                            <AlertCircle size={24} className="mb-2 opacity-50" />
                            <p className="text-xs font-medium">No data available for this filter</p>
                        </div>
                    ) : (
                        data.map((item, index) => (
                            <div key={index} className="group">
                                <div className="flex justify-between items-center mb-1">
                                    <span className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-0.5 rounded-md min-w-[24px] text-center mr-3">#{index + 1}</span>
                                    <span className="text-sm font-semibold text-gray-700 flex-grow truncate mr-4" title={item.name}>
                                        {item.name}
                                    </span>
                                    <span className="text-sm font-bold text-gray-900">{item.value}</span>
                                </div>
                                <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                                    <div 
                                        className={`h-full rounded-full ${barColorClass} transition-all duration-500 ease-out`} 
                                        style={{ width: `${(item.value / maxValue) * 100}%` }}
                                    ></div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            <AIInterpretation text={interpretation} loading={loadingInsights} />
        </div>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10 relative">
        <style>
          {`
            @media print {
              body * {
                visibility: hidden;
              }
              #printable-modal, #printable-modal * {
                visibility: visible;
              }
              #printable-modal {
                position: fixed;
                left: 0;
                top: 0;
                width: 100%;
                height: 100%;
                background: white;
                z-index: 9999;
                padding: 0;
                margin: 0;
                overflow: visible;
              }
              .no-print {
                display: none !important;
              }
              /* Print-specific table styling */
              table {
                  width: 100%;
                  border-collapse: collapse;
              }
              th, td {
                  border: 1px solid #ddd;
                  padding: 8px;
                  text-align: left;
                  font-size: 10px;
              }
              thead {
                  background-color: #f3f4f6;
                  -webkit-print-color-adjust: exact;
              }
            }
          `}
        </style>

        {/* === MODAL: STATUS DETAILS === */}
        {selectedStatusDetail && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 print:p-0">
                <div 
                    className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm animate-in fade-in duration-300 no-print"
                    onClick={() => setSelectedStatusDetail(null)}
                ></div>
                <div id="printable-modal" className="bg-white rounded-[2rem] shadow-2xl w-full max-w-6xl h-[85vh] relative z-10 flex flex-col animate-in zoom-in-95 duration-300 border border-white/20 overflow-hidden">

                    {/* Modal Header */}
                    <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                        <div className="flex items-center gap-4">
                            <div className={`p-3 rounded-xl no-print ${
                                selectedStatusDetail === 'Employed' ? 'bg-green-50 text-luGreen' :
                                selectedStatusDetail === 'Unemployed' ? 'bg-red-50 text-red-500' :
                                selectedStatusDetail === 'Self-employed' ? 'bg-amber-50 text-amber-500' :
                                'bg-gray-100 text-gray-500'
                            }`}>
                                {selectedStatusDetail === 'Employed' && <Briefcase size={24} />}
                                {selectedStatusDetail === 'Unemployed' && <AlertCircle size={24} />}
                                {selectedStatusDetail === 'Self-employed' && <Building2 size={24} />}
                                {selectedStatusDetail === 'Retired' && <UserCheck size={24} />}
                            </div>
                            <div>
                                <h3 className="text-2xl font-bold text-gray-800">{selectedStatusDetail} Report</h3>
                                <p className="text-sm text-gray-500">
                                    Generated List • {modalData.length} Records • Batch: {selectedYear} • Course: {selectedCourse}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2 no-print">
                            <button 
                                onClick={handlePrint}
                                className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white rounded-xl text-sm font-bold hover:bg-gray-800 transition-colors shadow-lg"
                            >
                                <Printer size={16} /> Print
                            </button>
                            <button 
                                onClick={() => setSelectedStatusDetail(null)}
                                className="p-2 text-gray-400 hover:text-gray-800 hover:bg-gray-100 rounded-full transition-colors"
                            >
                                <X size={24} />
                            </button>
                        </div>
                    </div>

                    {/* Modal Content (Table) */}
                    <div className="flex-grow overflow-auto p-0 bg-white">
                        {modalData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-gray-400 py-20">
                                <Users size={48} className="mb-4 opacity-30" />
                                <p className="font-semibold">No records found for this category.</p>
                            </div>
                        ) : (
                            <div className="w-full">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-50 border-b border-gray-200 sticky top-0 z-10">
                                        <tr>
                                            <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider w-1/4">Alumni Profile</th>

                                            {selectedStatusDetail === 'Employed' && (
                                                <>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Job Details</th>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Company Info</th>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider text-center">Stats</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Self-employed' && (
                                                <>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Business Info</th>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Location & Contact</th>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Details</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Unemployed' && (
                                                <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Reason provided</th>
                                            )}
                                            {selectedStatusDetail === 'Retired' && (
                                                <>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Retirement Info</th>
                                                    <th className="p-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Previous Employment</th>
                                                </>
                                            )}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-100">
                                        {modalData.map((record, idx) => (
                                            <tr key={idx} className="hover:bg-gray-50 transition-colors">
                                                <td className="p-4 align-top">
                                                    <div className="font-bold text-gray-800 text-sm">{record.full_name}</div>
                                                    <div className="text-xs text-gray-500 mt-0.5">{record.program}</div>
                                                    <div className="inline-block mt-1 px-2 py-0.5 bg-gray-100 text-gray-600 rounded text-[10px] font-bold">
                                                        Batch {record.year_level}
                                                    </div>
                                                </td>

                                                {selectedStatusDetail === 'Employed' && (
                                                    <>
                                                        <td className="p-4 align-top">
                                                            <div className="font-bold text-gray-700 text-sm">{record.current_position || 'N/A'}</div>
                                                            <div className="text-xs text-gray-500 mt-1 flex items-center gap-1">
                                                                <Award size={10} /> {record.current_job_level}
                                                            </div>
                                                            <div className="text-xs text-gray-500 mt-0.5 flex items-center gap-1">
                                                                <Calendar size={10} /> Hired: {record.date_hired || 'N/A'}
                                                            </div>
                                                        </td>
                                                        <td className="p-4 align-top">
                                                            <div className="font-semibold text-gray-700 text-sm">{record.company_name || 'N/A'}</div>
                                                            <div className="text-xs text-gray-500 mt-1 flex items-start gap-1">
                                                                <MapPin size={10} className="mt-0.5 shrink-0"/> {record.company_address || 'N/A'}
                                                            </div>
                                                            <div className="text-xs text-gray-500 mt-0.5">
                                                                Ind: {record.industry || 'N/A'}
                                                            </div>
                                                        </td>
                                                        <td className="p-4 align-top text-center">
                                                            <span className={`inline-block px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wide border ${
                                                                record.job_alignment === 'Related' 
                                                                ? 'bg-green-50 text-green-700 border-green-200' 
                                                                : 'bg-amber-50 text-amber-700 border-amber-200'
                                                            }`}>
                                                                {record.job_alignment || 'N/A'}
                                                            </span>
                                                        </td>
                                                    </>
                                                )}

                                                {selectedStatusDetail === 'Self-employed' && (
                                                    <>
                                                        <td className="p-4 align-top">
                                                            <div className="font-bold text-gray-700 text-sm">{record.business_name || 'N/A'}</div>
                                                            <div className="text-xs text-gray-500 mt-1">Role: {record.current_position || 'Owner'}</div>
                                                            <div className="text-xs text-gray-500 mt-0.5">Type: {record.business_type || 'N/A'}</div>
                                                        </td>
                                                        <td className="p-4 align-top">
                                                            <div className="text-xs text-gray-600 flex items-start gap-1 mb-1">
                                                                <MapPin size={12} className="mt-0.5 shrink-0"/> {record.business_address || 'N/A'}
                                                            </div>
                                                            <div className="text-xs text-gray-600 flex items-center gap-1">
                                                                <Phone size={12} /> {record.business_contact_no || 'N/A'}
                                                            </div>
                                                        </td>
                                                        <td className="p-4 align-top">
                                                            <div className="text-xs text-gray-500">Started: {record.business_duration || 'N/A'}</div>
                                                            <div className="text-xs text-gray-500 mt-1">Industry: {record.industry || 'N/A'}</div>
                                                        </td>
                                                    </>
                                                )}

                                                {selectedStatusDetail === 'Unemployed' && (
                                                    <td className="p-4 align-top">
                                                        <div className="p-2 bg-red-50 rounded-lg border border-red-100 inline-block">
                                                            <div className="text-xs font-bold text-red-600 uppercase tracking-wide mb-1">Primary Reason</div>
                                                            <div className="text-sm font-semibold text-gray-700">{record.unemployed_reasons || 'Not Specified'}</div>
                                                        </div>
                                                    </td>
                                                )}

                                                {selectedStatusDetail === 'Retired' && (
                                                    <>
                                                        <td className="p-4 align-top">
                                                            <div className="text-sm font-bold text-gray-700">{record.retirement_reason || 'N/A'}</div>
                                                            <div className="text-xs text-gray-500 mt-1">Retired: {record.date_retired || 'N/A'}</div>
                                                        </td>
                                                        <td className="p-4 align-top">
                                                            <div className="text-sm font-semibold text-gray-600">Prev. Company: {record.last_company || 'N/A'}</div>
                                                        </td>
                                                    </>
                                                )}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        )}

        {/* --- Header & Filter Section --- */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end gap-6 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 font-display">Analytics Overview</h2>
                <p className="text-gray-500 mt-1">Real-time data visualization of alumni employment status.</p>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
                {/* Year Filter */}
                <div className="relative group min-w-[140px]">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <TrendingUp size={16} className="text-gray-400 group-focus-within:text-luGreen"/>
                    </div>
                    <select 
