    // Profile Data
    full_name: string;
    program: string;
    year_level: string; // Batch
}

// Helper Component for Interpretation - NEOBRUTALIST STYLE
const InterpretationBlock = ({ text, loading }: { text?: string, loading: boolean }) => (
    <div className="mt-6 pt-4 border-t-2 border-black">
        <div className="flex flex-col gap-2">
            <h5 className="font-black text-xs uppercase tracking-widest text-black">Interpretation</h5>
