import React, { useEffect, useState, useMemo } from 'react';
import { Briefcase, AlertCircle, UserCheck, Target, Building2, BarChart3, PieChart as PieChartIcon, TrendingUp, Users, Filter, ChevronDown, RefreshCw, Award, X, MapPin, Printer, Calendar, Phone, Sparkles, BookOpen, Heart, Info } from 'lucide-react';
