              }
              /* Print-specific table styling */
              table {
                  width: 100%;
                  border-collapse: collapse;
                  border: 2px solid black;
              }
              th, td {
                  border: 1px solid black;
                  padding: 8px;
                  text-align: left;
                  font-size: 10px;
                  color: black;
              }
              thead {
                  background-color: #eee;
                  -webkit-print-color-adjust: exact;
