                <div className="bg-white p-6 border-2 border-black shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] flex flex-col justify-between">
                    <div>
                        <div className="flex items-center gap-3 mb-6 pb-4 border-b-2 border-black">
