                                    <p className="text-xs text-black font-bold uppercase bg-blue-200 px-2 mt-1">Aligned</p>
                                </div>
                            </div>
                        </div>
                    </div>
                    <InterpretationBlock text={interpretations?.alignment} loading={loadingInsights} />
                </div>
            </div>

            {/* LIST CARDS SECTION (Reasons & Details) */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

                {/* Top Unemployment Reasons */}
                <ReasonListCard 
                    title="Unemployment" 
                    icon={AlertCircle}
                    data={analytics.unemploymentReasonData}
                    colorClass="" // Unused in Neo
                    barColorClass="" // Unused in Neo
                    interpretation={interpretations?.unemployment}
                />

                {/* Misalignment Reasons */}
                <ReasonListCard 
                    title="Job Misalignment" 
                    icon={PieChartIcon}
                    data={analytics.alignmentReasonData}
                    colorClass=""
                    barColorClass=""
                    interpretation={interpretations?.misalignment}
                />

                {/* Retirement Reasons */}
                <ReasonListCard 
                    title="Retirement Reasons" 
                    icon={UserCheck}
                    data={analytics.retirementReasonData}
                    colorClass=""
                    barColorClass=""
                    interpretation={interpretations?.retirement}
                />

            </div>
        </>
        )}

        {/* === 2. EDUCATION TAB === */}
        {activeTab === 'education' && <EducationAnalytics />}

        {/* === 3. COMMUNITY TAB === */}
        {activeTab === 'community' && <CommunityAnalytics />}

        {/* === 4. SKILLS TAB === */}
        {activeTab === 'skills' && <SkillsAnalytics />}
    </div>
  );
};

