                        <div className="flex items-center gap-3 no-print">
                            <button onClick={handlePrint} className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white rounded-xl text-sm font-bold shadow-md hover:bg-slate-900 transition-all">
                                <Printer size={16} /> Print
                            </button>
                            <button onClick={() => setSelectedStatusDetail(null)} className="p-2 bg-white border border-gray-200 rounded-xl hover:bg-red-50 hover:text-red-500 hover:border-red-100 transition-all shadow-sm text-gray-400">
                                <X size={24} />
                            </button>
