                        </div>
                        <div className="flex-grow flex items-center justify-center relative min-h-[200px]">
                            <ResponsiveContainer width="100%" height={200}>
                                <PieChart>
                                    <Pie
                                        data={analytics.alignmentRate}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={60}
                                        outerRadius={80}
                                        paddingAngle={5}
                                        dataKey="value"
                                        stroke="none"
                                    >
                                        {analytics.alignmentRate.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={ALIGNMENT_COLORS[index % ALIGNMENT_COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', backgroundColor: 'rgba(255, 255, 255, 0.9)' }} />
                                </PieChart>
                            </ResponsiveContainer>
                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none pb-8">
                                <div className="text-center">
                                    <span className="text-4xl font-bold text-slate-800">
                                        {analytics.alignmentRate.length > 0 
                                            ? Math.round((analytics.alignmentRate[0].value / (analytics.alignmentRate[0].value + analytics.alignmentRate[1].value || 1)) * 100)
                                            : 0}%
                                    </span>
                                    <p className="text-xs text-indigo-500 font-bold uppercase">Aligned</p>
                                </div>
                            </div>
                        </div>
                        {/* Alignment Stats Breakdown */}
                        <div className="flex justify-around mt-4 pt-4 border-t border-slate-100">
                            <div className="text-center">
                                <div className="flex items-center justify-center gap-1 text-[10px] font-bold text-indigo-600 uppercase mb-0.5">
                                    <CheckCircle2 size={12} /> Related
                                </div>
                                <div className="text-lg font-black text-slate-800">{analytics.alignmentRate.find(x => x.name === 'Related')?.value || 0}</div>
                                <div className="text-[10px] text-slate-400">Graduates</div>
                            </div>
                            <div className="text-center">
                                <div className="flex items-center justify-center gap-1 text-[10px] font-bold text-purple-600 uppercase mb-0.5">
                                    <XCircle size={12} /> Non-Related
                                </div>
                                <div className="text-lg font-black text-slate-800">{analytics.alignmentRate.find(x => x.name === 'Non-Related')?.value || 0}</div>
                                <div className="text-[10px] text-slate-400">Graduates</div>
                            </div>
                        </div>
                    </div>
                    <InterpretationBlock text={interpretations?.alignment} loading={loadingInsights} />
                </div>
            </div>

            {/* LIST CARDS SECTION (Glass) */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

                <ReasonListCard 
                    title="Unemployment Reasons" 
                    icon={AlertCircle}
                    data={analytics.unemploymentReasonData}
                    colorClass="" 
                    barColorClass=""
                    interpretation={interpretations?.unemployment}
                />

                <ReasonListCard 
                    title="Job Misalignment Reasons" 
                    icon={PieChartIcon}
                    data={analytics.alignmentReasonData}
                    colorClass=""
                    barColorClass=""
                    interpretation={interpretations?.misalignment}
                />

                <ReasonListCard 
                    title="Retirement Reasons" 
                    icon={UserCheck}
                    data={analytics.retirementReasonData}
                    colorClass=""
                    barColorClass=""
                    interpretation={interpretations?.retirement}
                />

            </div>
        </>
        )}

        {/* === 2. EDUCATION TAB === */}
        {activeTab === 'education' && <EducationAnalytics />}

        {/* === 3. COMMUNITY TAB === */}
        {activeTab === 'community' && <CommunityAnalytics />}

        {/* === 4. SKILLS TAB === */}
        {activeTab === 'skills' && <SkillsAnalytics />}
    </div>
  );
};

export default HomePage;

