                    {/* Right: Misalignment Reasons */}
                    <div className="flex-1">
                         {analytics.alignmentRate.find(a => a.name === 'Non-Related' && a.value > 0) ? (
                            <div className="h-full flex flex-col">
                                 <div className="flex items-center gap-3 mb-6">
                                    <div className="p-2 bg-purple-100 text-purple-600 rounded-xl"><PieChartIcon size={20}/></div>
                                    <h4 className="font-bold text-slate-800">Job Misalignment Reasons</h4>
